<template>
  <section id="app">
    <Loading :loading="loading" :progress="progress" />
    <div v-if="step === -1" class="passworkbox">
      <p>请输入访问密码</p>
      <input v-model="password" />
      <button class="button" @click="openRoom">进入会议</button>
    </div>
    <template v-if="step > -1 && step < 3 && currentPage > 0">
      <ViewPDF
        :src="url"
        :page="currentPage"
        :rotate="rotate"
        @progress="onProgress"
        @page-loaded="onPageLoaded"
        @num-pages="onNumPages"
      />
    </template>
    <div class="prompt" v-if="step === 0">
      已加入，等待开始
    </div>
    <div class="prompt" v-if="step === 2">
      已暂停
    </div>
    <div class="prompt" v-if="step === 3">
      已结束
    </div>
  </section>
</template>

<script>
import Loading from '@/components/Load';
import pdfOperation from '../pdfOperation';
const getQueryString = (name) => {
  const reg = new RegExp(`(^|&)${name}=([^&]*)(&|$)`);
  const r = window.location.search.substr(1).match(reg);
  if (r != null) return unescape(r[2]);
  return null;
};

export default {
  mixins: [pdfOperation],
  data() {
    return {
      loading: false,
      socket: null,
      step: -1, // -1：输入密码；0: 进入 1：开始；2：暂停；3：结束
      password: '',
      room: '',
    };
  },
  created() {
    const room = getQueryString('room');
    if (!room) {
      alert('房间错误');
      return;
    }
    this.room = room;
  },
  mounted() {
  },
  components: {
    Loading,
  },
  computed: {
  },
  methods: {
    // 生产共享链接
    openRoom() {
      if (!this.password) {
        alert('请输入密码');
        return;
      }
      const url = `ws://wss.meeting.confmate.cn/ws/join?room_id=${this.room}&password=${this.password}`;
      const socket = new WebSocket(url);
      socket.onopen = this.onOpen;
      socket.onmessage = this.onMmessage;
      socket.onclose = this.onClose;
      socket.onerror = this.onError;
      this.socket = socket;
    },
    // 监听是否打开
    onOpen(event) {
      console.log('开启', event)
    },
    // 监听关闭
    onClose(event) {
      console.log('关闭了', event);
      this.step = -1;
      this.loading = false;
      this.socket = null;
      this.password  = '';
    },
    // 监听错误
    onError(event) {
      console.log('错误', event);
    },
    // 监听消息
    onMmessage({ data }) {
      const res = JSON.parse(data);
      if (!res.Success) {
        alert('密码错误');
        return;
      }
      if (res.Type === 1) {
        this.loading = true;
      }
      this.step = res.Type;
      this.jumpPage(res.Page);
    },
  },
};
</script>

